  const capsule = add(body, new THREE.CylinderGeometry(0.42, 0.42, 1.48, 24), shell);
  capsule.rotation.z = Math.PI / 2;
  add(body, new THREE.SphereGeometry(0.42, 24, 12), shell).position.x = -0.74;
