import * as THREE from "three";
import { LEVEL_ONE_RECORD_TYPES } from "./levelOneRecords.js";

// Meshes for the Level 1 shooter. Good targets are not random golden props:
// they are a consistent "record core" family. The player should read them by
// silhouette first: smooth capsule, protective ring/cage, clean trail, and a
// glow. Wreckage stays jagged, asymmetric, and unlabelled.

const RECORD_TYPES = LEVEL_ONE_RECORD_TYPES;

function shellMaterial() {
  return new THREE.MeshStandardMaterial({
    color: 0x171f27,
    metalness: 0.75,
    roughness: 0.42,
    flatShading: true,
  });
}

function brassMaterial() {
  return new THREE.MeshStandardMaterial({
    color: 0xe0a838,
    emissive: 0x6a4310,
    emissiveIntensity: 0.5,
    metalness: 0.95,
    roughness: 0.28,
  });
}

function glassMaterial() {
  return new THREE.MeshStandardMaterial({
    color: 0x7feaff,
    emissive: 0x1ca7c7,
    emissiveIntensity: 1.25,
    metalness: 0.1,
    roughness: 0.18,
    transparent: true,
    opacity: 0.86,
  });
}

function darkMetal() {
  return new THREE.MeshStandardMaterial({
    color: 0x2f333a,
    metalness: 0.25,
    roughness: 0.95,
    flatShading: true,
  });
}

function burnMaterial() {
  return new THREE.MeshBasicMaterial({
    color: 0xff5a3c,
    transparent: true,
    opacity: 0.75,
    blending: THREE.AdditiveBlending,
    depthWrite: false,
    fog: false,
  });
}

function add(group, geo, mat) {
  const m = new THREE.Mesh(geo, mat);
  group.add(m);
  return m;
}

function partMaterials() {
  return {
